import { getAllPosts, getAllPages, getAllCategories } from './admin-api';

export async function getCategories(perPage = 50) {
  const categories = await getAllCategories();
  return categories.slice(0, perPage).map(cat => ({
    id: parseInt(cat.id),
    name: cat.name,
    slug: cat.slug,
    count: 0,
    parent: 0,
    link: `/category/${cat.slug}`,
  }));
}

export async function getLatestPosts(perPage = 12) {
  const posts = await getAllPosts();
  const publishedPosts = posts
    .filter(post => post.status === 'publish')
    .sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
    .slice(0, perPage);
  
  return publishedPosts.map(post => ({
    id: parseInt(post.id),
    date: post.createdAt,
    modified: post.updatedAt,
    slug: post.slug,
    link: `/blog/${post.slug}`,
    title: { rendered: post.title },
    content: { rendered: post.content, protected: false },
    excerpt: { rendered: post.excerpt || '', protected: false },
    author: 1,
    featured_media: 0,
    categories: post.categories.map(catId => parseInt(catId)).filter(id => !isNaN(id)),
    _embedded: {
      'wp:featuredmedia': [],
      author: [{ id: 1, name: post.author }],
      'wp:term': [],
    },
  }));
}

export async function getPostsByCategorySlug(slug: string, perPage = 12) {
  const categories = await getAllCategories();
  const category = categories.find(cat => cat.slug === slug);
  if (!category) return { category: null, posts: [] };

  const posts = await getAllPosts();
  const categoryPosts = posts
    .filter(post => post.status === 'publish' && post.categories.includes(slug))
    .sort((a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime())
    .slice(0, perPage);

  const formattedPosts = categoryPosts.map(post => ({
    id: parseInt(post.id),
    date: post.createdAt,
    modified: post.updatedAt,
    slug: post.slug,
    link: `/blog/${post.slug}`,
    title: { rendered: post.title },
    content: { rendered: post.content, protected: false },
    excerpt: { rendered: post.excerpt || '', protected: false },
    author: 1,
    featured_media: 0,
    categories: post.categories.map(catId => parseInt(catId)).filter(id => !isNaN(id)),
    _embedded: {
      'wp:featuredmedia': [],
      author: [{ id: 1, name: post.author }],
      'wp:term': [],
    },
  }));

  return {
    category: {
      id: parseInt(category.id),
      name: category.name,
      slug: category.slug,
      count: formattedPosts.length,
      parent: 0,
      link: `/category/${category.slug}`,
    },
    posts: formattedPosts,
  };
}

export async function getPostBySlug(slug: string) {
  const posts = await getAllPosts();
  const post = posts.find(p => p.slug === slug);
  if (!post || post.status !== 'publish') return null;

  return {
    id: parseInt(post.id),
    date: post.createdAt,
    modified: post.updatedAt,
    slug: post.slug,
    link: `/blog/${post.slug}`,
    title: { rendered: post.title },
    content: { rendered: post.content, protected: false },
    excerpt: { rendered: post.excerpt || '', protected: false },
    author: 1,
    featured_media: 0,
    categories: post.categories.map(catId => parseInt(catId)).filter(id => !isNaN(id)),
    _embedded: {
      'wp:featuredmedia': [],
      author: [{ id: 1, name: post.author }],
      'wp:term': [],
    },
  };
}

export async function getPageBySlug(slug: string) {
  const pages = await getAllPages();
  const page = pages.find(p => p.slug === slug);
  if (!page || page.status !== 'publish') return null;

  return {
    id: parseInt(page.id),
    slug: page.slug,
    title: { rendered: page.title },
    content: { rendered: page.content, protected: false },
    excerpt: { rendered: page.excerpt || '', protected: false },
    featured_media: 0,
    _embedded: {
      'wp:featuredmedia': [],
      author: [{ id: 1, name: page.author }],
      'wp:term': [],
    },
  };
}